  /**
   * Generate a fresh package-lock.json from package.json
   * This is the starting point for any new project or when
   * you need to regenerate the lock file from scratch.
   */
  generateLockFile() {
    console.log('🔒 Generating package-lock.json...\n');

    // Verify package.json exists
    if (!fs.existsSync(this.packageJsonPath)) {
      throw new Error(
        'package.json not found. Initialize your project first with: npm init'
      );
    }

    try {
      // npm install generates/updates package-lock.json
      // --package-lock-only: Only update the lock file without installing node_modules
      execSync('npm install --package-lock-only', {
        cwd: this.projectRoot,
        stdio: 'inherit',
      });

      console.log('\n✅ package-lock.json generated successfully.');
      this.printLockFileStats();
    } catch (error) {
      console.error('❌ Failed to generate package-lock.json:', error.message);
      throw error;
    }
  }

  /**
   * Install dependencies using the exact versions from package-lock.json
   * This is the command that should be used in CI/CD pipelines
   * and deployment environments.
   *
   * `npm ci` (Clean Install):
   * - Removes existing node_modules
   * - Installs exact versions from package-lock.json
   * - Fails if package-lock.json is out of sync with package.json
   * - Faster and more reliable than `npm install` for CI
   */
  cleanInstall() {
    console.log('🚀 Running clean install (npm ci)...\n');

    if (!fs.existsSync(this.packageLockPath)) {
      throw new Error(
        'package-lock.json not found. Run generateLockFile() first.'
      );
    }

    try {
      execSync('npm ci', {
        cwd: this.projectRoot,
        stdio: 'inherit',
      });
      console.log('\n✅ Clean install completed. Dependencies match lock file exactly.');
    } catch (error) {
      console.error('❌ Clean install failed:', error.message);
      console.error(
        '   This usually means package-lock.json is out of sync with package.json.'
      );
      console.error('   Run `npm install` to update the lock file, then commit it.');
      throw error;
    }
  }

  // ============================================================
  // SECTION 2: Lock File Validation & Integrity
  // ============================================================

  /**
   * Validate that package-lock.json is in sync with package.json
   * This should be run as a pre-commit hook or in CI pipelines.
   */
  validateLockFile() {
    console.log('🔍 Validating package-lock.json...\n');

    if (!fs.existsSync(this.packageLockPath)) {
      console.error('❌ package-lock.json does not exist!');
      return { valid: false, reason: 'MISSING_LOCK_FILE' };
    }

    const packageJson = JSON.parse(fs.readFileSync(this.packageJsonPath, 'utf8'));
    const packageLock = JSON.parse(fs.readFileSync(this.packageLockPath, 'utf8'));

    const issues = [];

    // Check lockfile version (v2/v3 is recommended for npm 7+)
    if (packageLock.lockfileVersion < 2) {
      issues.push({
        severity: 'warning',
        message: `Lock file version is ${packageLock.lockfileVersion}. Consider upgrading to v2/v3 (npm 7+).`,
      });
    }

    // Check that all dependencies in package.json are in the lock file
    const allDeps = {
      ...packageJson.dependencies,
      ...packageJson.devDependencies,
      ...packageJson.optionalDependencies,
    };

    const lockPackages = packageLock.packages || {};
    const lockDependencies = packageLock.dependencies || {};

    for (const [depName, depVersion] of Object.entries(allDeps)) {
      // Check in v2/v3 format (packages)
      const lockEntry =
        lockPackages[`node_modules/${depName}`] || lockDependencies[depName];

      if (!lockEntry) {
        issues.push({
          severity: 'error',
          message: `Dependency "${depName}@${depVersion}" is in package.json but missing from lock file.`,
        });
      }
    }

    // Check for integrity hashes
    let missingIntegrity = 0;
    for (const [pkgPath, pkgInfo] of Object.entries(lockPackages)) {
      if (pkgPath && pkgPath !== '' && !pkgInfo.link && !pkgInfo.integrity) {
        missingIntegrity++;
      }
    }

    if (missingIntegrity > 0) {
      issues.push({
        severity: 'warning',
        message: `${missingIntegrity} packages are missing integrity hashes.`,
      });
    }

    // Report results
    const errors = issues.filter((i) => i.severity === 'error');
    const warnings = issues.filter((i) => i.severity === 'warning');

    if (errors.length > 0) {
      console.error('❌ Validation FAILED:\n');
      errors.forEach((e) => console.error(`  ERROR: ${e.message}`));
      warnings.forEach((w) => console.warn(`  WARNING: ${w.message}`));
      return { valid: false, reason: 'OUT_OF_SYNC', issues };
    }

    if (warnings.length > 0) {
      warnings.forEach((w) => console.warn(`  ⚠️  WARNING: ${w.message}`));
    }

    console.log('✅ package-lock.json is valid and in sync with package.json.');
    return { valid: true, issues };
  }

  /**
   * Compute a checksum of the lock file for cache-busting
   * and verification across environments.
   */
  computeLockFileChecksum() {
    if (!fs.existsSync(this.packageLockPath)) {
      return null;
    }

    const content = fs.readFileSync(this.packageLockPath, 'utf8');
    const hash = crypto.createHash('sha256').update(content).digest('hex');

    console.log(`📋 Lock file checksum (SHA-256): ${hash}`);
    return hash;
  }

