  /**
   * Create a timestamped backup of the current lock file.
   */
  backupLockFile() {
    if (!fs.existsSync(this.packageLockPath)) {
      console.log('ℹ️  No lock file to backup.');
      return null;
    }

    if (!fs.existsSync(this.lockfileBackupDir)) {
      fs.mkdirSync(this.lockfileBackupDir, { recursive: true });
    }

    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    const backupPath = path.join(
      this.lockfileBackupDir,
      `package-lock.${timestamp}.json`
    );

    fs.copyFileSync(this.packageLockPath, backupPath);
    console.log(`💾 Lock file backed up to: ${backupPath}`);

    // Keep only the last 10 backups
    this.cleanOldBackups(10);

    return backupPath;
  }

  /**
   * Restore the most recent backup of the lock file.
   */
  restoreLockFile() {
    if (!fs.existsSync(this.lockfileBackupDir)) {
      console.error('❌ No backups found.');
      return false;
    }

    const backups = fs
      .readdirSync(this.lockfileBackupDir)
      .filter((f) => f.startsWith('package-lock.') && f.endsWith('.json'))
      .sort()
      .reverse();

    if (backups.length === 0) {
      console.error('❌ No backups found.');
      return false;
    }

    const latestBackup = path.join(this.lockfileBackupDir, backups[0]);
    fs.copyFileSync(latestBackup, this.packageLockPath);
    console.log(`♻️  Lock file restored from: ${latestBackup}`);
    return true;
  }

  /**
   * Clean old backups, keeping only the specified number.
   */
  cleanOldBackups(keepCount = 10) {
    if (!fs.existsSync(this.lockfileBackupDir)) return;

    const backups = fs
      .readdirSync(this.lockfileBackupDir)
      .filter((f) => f.startsWith('package-lock.') && f.endsWith('.json'))
      .sort()
      .reverse();

    if (backups.length > keepCount) {
      const toDelete = backups.slice(keepCount);
      toDelete.forEach((backup) => {
        fs.unlinkSync(path.join(this.lockfileBackupDir, backup));
      });
      console.log(`🧹 Cleaned ${toDelete.length} old backup(s).`);
    }
  }

